// Initial Implementation

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  const url = new URL(request.url);
  if (url.pathname === '/public') {
    return await publicWorker(request);
  } else if (url.pathname.startsWith('/internal')) {
    return await internalWorker(url.pathname.split('/')[1], request);
  }
}

async function publicWorker(request) {
  try {
    const response = await fetch('https://example.com/public', { method: 'GET' });
    return new Response(response.body, response);
  } catch (error) {
    console.error(error);
    return new Response(null, { status: 500 });
  }
}

async function internalWorker(serviceName, request) {
  try {
    const binding = await getBinding('internal-worker-' + serviceName);
    if (!binding) {
      throw new Error(`Service Binding not found for ${serviceName}`);
    }
    const response = await fetch(binding.url, { method: 'GET' });
    return new Response(response.body, response);
  } catch (error) {
    console.error(error);
    return new Response(null, { status: 500 });
  }
}

async function getBinding(name) {
  try {
    const bindings = await context.bindings;
    return bindings[name];
  } catch (error) {
    throw new Error(`Failed to retrieve Service Binding for ${name}`);
  }
}